5.2 Create services/moneroService.js

javascript

const axios = require('axios');

const crypto = require('crypto');

// Configuration from environment

const RPC_URL = process.env.MONERO_RPC_URL || 'http://127.0.0.1:18083/json_rpc';

const WALLET_ADDRESS = process.env.MONERO_WALLET_ADDRESS || 'XXXX';

const NETWORK = process.env.MONERO_NETWORK || 'testnet';

const CONFIRMATIONS_REQUIRED = parseInt(process.env.MONERO_CONFIRMATIONS || '1', 10);

/**

•
JSON-RPC call to Monero wallet

*/

const rpc = async (method, params = {}) => {

try {

const response = await axios.post(RPC_URL, {

jsonrpc: '2.0',

id: crypto.randomBytes(8).toString('hex'),

method,

params,

}, {

timeout: 30000,

headers: { 'Content-Type': 'application/json' },

});

if (response.data.error) {

throw new Error(Monero RPC error: ${response.data.error.message});

}

return response.data.result;

} catch (error) {

console.error([Monero RPC] Method ${method} failed:, error.response?.data || error.message);

throw new Error(Monero RPC error: ${method} - ${error.message});

}

};

/**

• Generate a subaddress for an order
*/
const generateSubaddress = async (label = '') => {
const result = await rpc('create_address', {
label: label.slice(0, 64), // Max 64 chars
account_index: 0
});

return {

address: result.address,

index: result.address_index,

label: result.label || label,

};

};

/**

• Get wallet balance
*/
const getBalance = async (accountIndex = 0) => {
const result = await rpc('get_balance', {
account_index: accountIndex
});

return {

balance: result.balance / 1e12, // Convert from atomic units

unlockedBalance: result.unlocked_balance / 1e12,

blocksToUnlock: result.blocks_to_unlock || 0,

};

};

/**

• Check if a subaddress received a payment
*/
const checkPayment = async (address, expectedAmount, confirmations = CONFIRMATIONS_REQUIRED) => {
// Get all incoming transfers
const transfers = await rpc('get_transfers', {
in: true,
account_index: 0,
filter_by_height: true,
min_height: 0,
});

const incoming = transfers.in || [];

const pending = transfers.pending || [];

// Check confirmed transfers

for (const tx of incoming) {

if (tx.address === address &&

tx.amount / 1e12 >= expectedAmount &&

tx.confirmations >= confirmations) {

return {

received: true,

amount: tx.amount / 1e12,

txid: tx.txid,

confirmations: tx.confirmations,

timestamp: tx.timestamp,

blockHeight: tx.height,

isConfirmed: true,

};

}

}

// Check pending (unconfirmed) transfers

for (const tx of pending) {

if (tx.address === address && tx.amount / 1e12 >= expectedAmount) {

return {

received: true,

amount: tx.amount / 1e12,

txid: tx.txid,

confirmations: 0,

timestamp: tx.timestamp,

blockHeight: null,

isConfirmed: false,

};

}

}

return { received: false };

};

/**

• Send XMR from wallet
*/
const sendPayment = async (destinationAddress, amount, priority = 1) => {
const result = await rpc('transfer', {
destinations: [{
address: destinationAddress,
amount: Math.floor(amount * 1e12) // Convert to atomic units
}],
priority, // 1 = default, 2 = unimportant, 3 = normal, 4 = elevated, 5 = priority
ring_size: 7, // Standard ring size
get_tx_key: true,
do_not_relay: false,
});

return {

txid: result.tx_hash,

txKey: result.tx_key,

amount: amount,

fee: result.fee / 1e12,

multiSigTx: result.multisig_tx || false,

};

};

/**

• Get transaction details
*/
const getTransaction = async (txid) => {
const result = await rpc('get_transfer_by_txid', { txid });
return {
txid: result.txid,
amount: result.amount / 1e12,
fee: result.fee / 1e12,
confirmations: result.confirmations,
timestamp: result.timestamp,
address: result.address,
destination: result.destinations || [],
};
};

/**

• Get all subaddresses
*/
const getSubaddresses = async (accountIndex = 0) => {
const result = await rpc('get_address', {
account_index: accountIndex,
view_all: true,
});
return result.addresses.map(addr => ({
address: addr.address,
index: addr.address_index,
label: addr.label || '',
}));
};

module.exports = {

rpc,

generateSubaddress,

getBalance,

checkPayment,

sendPayment,

getTransaction,

getSubaddresses,

};

